1	import { useState, useEffect, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Textarea } from "@/components/ui/textarea";
8	import {
9	  Select,
10	  SelectContent,
11	  SelectItem,
12	  SelectTrigger,
13	  SelectValue,
14	} from "@/components/ui/select";
15	import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
16	import {
17	  Building2,
18	  Camera,
19	  Save,
20	  CreditCard,
21	  FileText,
22	  Sparkles,
23	} from "lucide-react";
24	import { toast } from "sonner";
25	
26	const currencies = [
27	  { code: "KES", name: "Kenyan Shilling" },
28	  { code: "USD", name: "US Dollar" },
29	  { code: "EUR", name: "Euro" },
30	  { code: "GBP", name: "British Pound" },
31	  { code: "NGN", name: "Nigerian Naira" },
32	  { code: "ZAR", name: "South African Rand" },
33	  { code: "GHS", name: "Ghanaian Cedi" },
34	  { code: "TZS", name: "Tanzanian Shilling" },
35	  { code: "UGX", name: "Ugandan Shilling" },
36	];
37	
38	const StudioSettingsTab = () => {
39	  const [loading, setLoading] = useState(true);
40	  const [saving, setSaving] = useState(false);
41	  const [uploading, setUploading] = useState(false);
42	  const fileInputRef = useRef<HTMLInputElement>(null);
43	
44	  const [settings, setSettings] = useState({
45	    business_name: "",
46	    business_email: "",
47	    business_phone: "",
48	    business_address: "",
49	    logo_url: "",
50	    tax_id: "",
51	    default_currency: "KES",
52	    default_tax_rate: 0,
53	    default_payment_terms: "Payment is due within 30 days of invoice date.",
54	    bank_name: "",
55	    bank_account_name: "",
56	    bank_account_number: "",
57	    mpesa_till_number: "",
58	  });
59	
60	  const [settingsId, setSettingsId] = useState<string | null>(null);
61	
62	  useEffect(() => {
63	    fetchSettings();
64	  }, []);
65	
66	  const fetchSettings = async () => {
67	    const { data: { session } } = await supabase.auth.getSession();
68	    if (!session) return;
69	
70	    const { data } = await supabase
71	      .from("business_settings")
72	      .select("*")
73	      .eq("user_id", session.user.id)
74	      .single();
75	
76	    if (data) {
77	      setSettingsId(data.id);
78	      setSettings({
79	        business_name: data.business_name || "",
80	        business_email: data.business_email || "",
81	        business_phone: data.business_phone || "",
82	        business_address: data.business_address || "",
83	        logo_url: data.logo_url || "",
84	        tax_id: data.tax_id || "",
85	        default_currency: data.default_currency || "KES",
86	        default_tax_rate: Number(data.default_tax_rate) || 0,
87	        default_payment_terms: data.default_payment_terms || "",
88	        bank_name: data.bank_name || "",
89	        bank_account_name: data.bank_account_name || "",
90	        bank_account_number: data.bank_account_number || "",
91	        mpesa_till_number: data.mpesa_till_number || "",
92	      });
93	    } else {
94	      // Pre-fill from profile
95	      const { data: profile } = await supabase
96	        .from("profiles")
97	        .select("*")
98	        .eq("id", session.user.id)
99	        .single();
100	
101	      if (profile) {
102	        setSettings((prev) => ({
103	          ...prev,
104	          business_name: profile.display_name || "",
105	          business_email: profile.email || "",
106	          logo_url: profile.avatar_url || "",
107	        }));
108	      }
109	    }
110	
111	    setLoading(false);
112	  };
113	
114	  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
115	    const file = e.target.files?.[0];
116	    if (!file) return;
117	
118	    if (!file.type.startsWith("image/")) {
119	      toast.error("Please upload an image file");
120	      return;
121	    }
122	    if (file.size > 5 * 1024 * 1024) {
123	      toast.error("Max 5MB allowed");
124	      return;
125	    }
126	
127	    setUploading(true);
128	
129	    const { data: { session } } = await supabase.auth.getSession();
130	    if (!session) return;
131	
132	    const fileExt = file.name.split(".").pop();
133	    const filePath = `business-logos/${session.user.id}-${Date.now()}.${fileExt}`;
134	
135	    const { error: uploadError } = await supabase.storage
136	      .from("chat-files")
137	      .upload(filePath, file);
138	
139	    if (uploadError) {
140	      toast.error("Upload failed: " + uploadError.message);
141	      setUploading(false);
142	      return;
143	    }
144	
145	    const { data: { publicUrl } } = supabase.storage.from("chat-files").getPublicUrl(filePath);
146	    setSettings((prev) => ({ ...prev, logo_url: publicUrl }));
147	    setUploading(false);
148	    if (fileInputRef.current) fileInputRef.current.value = "";
149	    toast.success("Logo uploaded!");
150	  };
151	
152	  const handleSave = async () => {
153	    setSaving(true);
154	    const { data: { session } } = await supabase.auth.getSession();
155	    if (!session) {
156	      toast.error("Please log in");
157	      setSaving(false);
158	      return;
159	    }
160	
161	    if (settingsId) {
162	      const { error } = await supabase
163	        .from("business_settings")
164	        .update(settings)
165	        .eq("id", settingsId);
166	
167	      if (error) {
168	        toast.error("Failed to save: " + error.message);
169	      } else {
170	        toast.success("Settings saved!");
171	      }
172	    } else {
173	      const { data, error } = await supabase
174	        .from("business_settings")
175	        .insert({ ...settings, user_id: session.user.id })
176	        .select()
177	        .single();
178	
179	      if (error) {
180	        toast.error("Failed to save: " + error.message);
181	      } else {
182	        setSettingsId(data.id);
183	        toast.success("Settings saved!");
184	      }
185	    }
186	
187	    setSaving(false);
188	  };
189	
190	  if (loading) {
191	    return (
192	      <div className="p-6 md:p-8 space-y-6">
193	        <div className="animate-pulse space-y-6">
194	          <div className="h-12 bg-muted rounded-xl w-2/5" />
195	          <div className="h-64 bg-muted rounded-2xl" />
196	          <div className="h-48 bg-muted rounded-2xl" />
197	        </div>
198	      </div>
199	    );
200	  }
201	
202	  return (
203	    <div className="p-4 md:p-8 space-y-6 max-w-4xl mx-auto">
204	      {/* Header */}
205	      <div>
206	        <h2 className="font-vollkorn text-2xl md:text-3xl font-bold text-foreground tracking-tight">
207	          Studio Settings
208	        </h2>
209	        <p className="text-sm text-muted-foreground mt-1">
210	          Configure your business details for invoices, receipts, and contracts
211	        </p>
212	      </div>
213	
214	      {/* Business Profile */}
215	      <Card className="p-6 border-0 shadow-sm">
216	        <div className="flex items-center gap-3 mb-6">
217	          <div className="p-2.5 rounded-xl bg-bronze/15">
218	            <Building2 className="h-5 w-5 text-bronze" />
219	          </div>
220	          <h3 className="font-vollkorn text-xl font-bold">Business Profile</h3>
221	        </div>
222	
223	        <div className="space-y-6">
224	          {/* Logo */}
225	          <div className="flex items-center gap-6">
226	            <input
227	              ref={fileInputRef}
228	              type="file"
229	              accept="image/*"
230	              className="hidden"
231	              onChange={handleLogoUpload}
232	            />
233	            <div
234	              className="relative group cursor-pointer"
235	              onClick={() => fileInputRef.current?.click()}
236	            >
237	              <Avatar className="h-20 w-20 ring-4 ring-bronze/20">
238	                <AvatarImage src={settings.logo_url} />
239	                <AvatarFallback className="bg-bronze/10 text-bronze text-xl font-bold">
240	                  {settings.business_name?.[0]?.toUpperCase() || "B"}
241	                </AvatarFallback>
242	              </Avatar>
243	              <div className="absolute inset-0 rounded-full bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
244	                <Camera className="h-5 w-5 text-white" />
245	              </div>
246	              {uploading && (
247	                <div className="absolute inset-0 rounded-full bg-black/60 flex items-center justify-center">
248	                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
249	                </div>
250	              )}
251	            </div>
252	            <div>
253	              <p className="font-medium text-foreground">Business Logo</p>
254	              <p className="text-xs text-muted-foreground">Appears on invoices, receipts & contracts. Max 5MB.</p>
255	            </div>
256	          </div>
257	
258	          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
259	            <div>
260	              <Label>Business Name</Label>
261	              <Input
262	                value={settings.business_name}
263	                onChange={(e) => setSettings({ ...settings, business_name: e.target.value })}
264	                placeholder="Your Business Name"
265	                className="mt-1"
266	              />
267	            </div>
268	            <div>
269	              <Label>Business Email</Label>
270	              <Input
271	                type="email"
272	                value={settings.business_email}
273	                onChange={(e) => setSettings({ ...settings, business_email: e.target.value })}
274	                placeholder="billing@yourbusiness.com"
275	                className="mt-1"
276	              />
277	            </div>
278	            <div>
279	              <Label>Phone Number</Label>
280	              <Input
281	                value={settings.business_phone}
282	                onChange={(e) => setSettings({ ...settings, business_phone: e.target.value })}
283	                placeholder="+254 7XX XXX XXX"
284	                className="mt-1"
285	              />
286	            </div>
287	            <div>
288	              <Label>Tax ID / PIN</Label>
289	              <Input
290	                value={settings.tax_id}
291	                onChange={(e) => setSettings({ ...settings, tax_id: e.target.value })}
292	                placeholder="P00XXXXXXX"
293	                className="mt-1"
294	              />
295	            </div>
296	          </div>
297	          <div>
298	            <Label>Business Address</Label>
299	            <Textarea
300	              value={settings.business_address}
301	              onChange={(e) => setSettings({ ...settings, business_address: e.target.value })}
302	              placeholder="Street, City, Country"
303	              className="mt-1"
304	              rows={2}
305	            />
306	          </div>
307	        </div>
308	      </Card>
309	
310	      {/* Invoice & Receipt Defaults */}
311	      <Card className="p-6 border-0 shadow-sm">
312	        <div className="flex items-center gap-3 mb-6">
313	          <div className="p-2.5 rounded-xl bg-emerald-500/15">
314	            <FileText className="h-5 w-5 text-emerald-500" />
315	          </div>
316	          <h3 className="font-vollkorn text-xl font-bold">Invoice & Receipt Defaults</h3>
317	        </div>
318	
319	        <div className="space-y-4">
320	          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
321	            <div>
322	              <Label>Default Currency</Label>
323	              <Select
324	                value={settings.default_currency}
325	                onValueChange={(v) => setSettings({ ...settings, default_currency: v })}
326	              >
327	                <SelectTrigger className="mt-1">
328	                  <SelectValue />
329	                </SelectTrigger>
330	                <SelectContent>
331	                  {currencies.map((c) => (
332	                    <SelectItem key={c.code} value={c.code}>
333	                      {c.code} - {c.name}
334	                    </SelectItem>
335	                  ))}
336	                </SelectContent>
337	              </Select>
338	            </div>
339	            <div>
340	              <Label>Default Tax Rate (%)</Label>
341	              <Input
342	                type="number"
343	                value={settings.default_tax_rate}
344	                onChange={(e) => setSettings({ ...settings, default_tax_rate: Number(e.target.value) })}
345	                className="mt-1"
346	                min={0}
347	                max={100}
348	              />
349	            </div>
350	          </div>
351	          <div>
352	            <Label>Default Payment Terms</Label>
353	            <Textarea
354	              value={settings.default_payment_terms}
355	              onChange={(e) => setSettings({ ...settings, default_payment_terms: e.target.value })}
356	              placeholder="Payment terms..."
357	              className="mt-1"
358	              rows={2}
359	            />
360	          </div>
361	        </div>
362	      </Card>
363	
364	      {/* Payment Details */}
365	      <Card className="p-6 border-0 shadow-sm">
366	        <div className="flex items-center gap-3 mb-6">
367	          <div className="p-2.5 rounded-xl bg-blue-500/15">
368	            <CreditCard className="h-5 w-5 text-blue-500" />
369	          </div>
370	          <h3 className="font-vollkorn text-xl font-bold">Payment Details</h3>
371	          <p className="text-xs text-muted-foreground ml-auto">Shown on invoices & receipts</p>
372	        </div>
373	
374	        <div className="space-y-4">
375	          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
376	            <div>
377	              <Label>Bank Name</Label>
378	              <Input
379	                value={settings.bank_name}
380	                onChange={(e) => setSettings({ ...settings, bank_name: e.target.value })}
381	                placeholder="e.g. Equity Bank"
382	                className="mt-1"
383	              />
384	            </div>
385	            <div>
386	              <Label>Account Name</Label>
387	              <Input
388	                value={settings.bank_account_name}
389	                onChange={(e) => setSettings({ ...settings, bank_account_name: e.target.value })}
390	                placeholder="Account holder name"
391	                className="mt-1"
392	              />
393	            </div>
394	            <div>
395	              <Label>Account Number</Label>
396	              <Input
397	                value={settings.bank_account_number}
398	                onChange={(e) => setSettings({ ...settings, bank_account_number: e.target.value })}
399	                placeholder="XXXXXXXXXX"
400	                className="mt-1"
401	              />
402	            </div>
403	            <div>
404	              <Label>M-Pesa Till/Paybill</Label>
405	              <Input
406	                value={settings.mpesa_till_number}
407	                onChange={(e) => setSettings({ ...settings, mpesa_till_number: e.target.value })}
408	                placeholder="Till or Paybill number"
409	                className="mt-1"
410	              />
411	            </div>
412	          </div>
413	        </div>
414	      </Card>
415	
416	      {/* Save Button */}
417	      <Button
418	        onClick={handleSave}
419	        disabled={saving}
420	        className="w-full gap-2 bg-bronze hover:bg-bronze/90 shadow-lg shadow-bronze/20 h-12"
421	      >
422	        <Save className="h-4 w-4" />
423	        {saving ? "Saving..." : "Save Settings"}
424	      </Button>
425	    </div>
426	  );
427	};
428	
429	export default StudioSettingsTab;
