1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { 
7	  Plus, 
8	  Search, 
9	  FileText, 
10	  Send, 
11	  Eye,
12	  MoreHorizontal,
13	  Edit,
14	  Trash2,
15	  CheckCircle2,
16	  Clock,
17	  AlertCircle,
18	  XCircle,
19	  Receipt,
20	  Copy,
21	  Filter,
22	  ArrowUpDown,
23	  TrendingUp,
24	  DollarSign,
25	  Sparkles,
26	} from "lucide-react";
27	import { toast } from "sonner";
28	import { format, isAfter } from "date-fns";
29	import {
30	  DropdownMenu,
31	  DropdownMenuContent,
32	  DropdownMenuItem,
33	  DropdownMenuSeparator,
34	  DropdownMenuTrigger,
35	} from "@/components/ui/dropdown-menu";
36	import {
37	  Select,
38	  SelectContent,
39	  SelectItem,
40	  SelectTrigger,
41	  SelectValue,
42	} from "@/components/ui/select";
43	import CreateInvoiceDialog from "./CreateInvoiceDialog";
44	import { useSubscription } from "@/hooks/use-subscription";
45	import InvoicePreviewDialog from "./InvoicePreviewDialog";
46	import ReceiptPreviewDialog from "./ReceiptPreviewDialog";
47	
48	interface Invoice {
49	  id: string;
50	  invoice_number: string;
51	  client_name: string;
52	  client_email: string | null;
53	  issue_date: string;
54	  due_date: string;
55	  status: string;
56	  subtotal: number;
57	  total: number;
58	  currency: string;
59	  created_at: string;
60	}
61	
62	const SmartInvoicesTab = ({ workspaceId }: { workspaceId?: string } = {}) => {
63	  const [invoices, setInvoices] = useState<Invoice[]>([]);
64	  const [loading, setLoading] = useState(true);
65	  const [searchQuery, setSearchQuery] = useState("");
66	  const [statusFilter, setStatusFilter] = useState("all");
67	  const [sortBy, setSortBy] = useState<"newest" | "oldest" | "amount">("newest");
68	  const { limits, isFree } = useSubscription();
69	  const [createDialogOpen, setCreateDialogOpen] = useState(false);
70	  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);
71	  const [previewInvoice, setPreviewInvoice] = useState<Invoice | null>(null);
72	  const [receiptInvoice, setReceiptInvoice] = useState<Invoice | null>(null);
73	  const [businessSettings, setBusinessSettings] = useState<{
74	    business_name: string;
75	    business_email: string;
76	    business_phone: string;
77	    business_address: string;
78	    logo_url: string;
79	    tax_id: string;
80	    default_currency: string;
81	    default_tax_rate: number;
82	    default_payment_terms: string;
83	  } | null>(null);
84	
85	  const fetchInvoices = async () => {
86	    const { data: { session } } = await supabase.auth.getSession();
87	    if (!session) return;
88	
89	    if (workspaceId) {
90	      const { data: msgs } = await supabase
91	        .from("chat_messages")
92	        .select("invoice_id")
93	        .eq("room_id", workspaceId)
94	        .not("invoice_id", "is", null);
95	      const ids = [...new Set((msgs || []).map((m: any) => m.invoice_id).filter(Boolean))];
96	      if (ids.length === 0) { setInvoices([]); setLoading(false); return; }
97	      const { data, error } = await supabase.from("invoices").select("*").in("id", ids).order("created_at", { ascending: false });
98	      if (error) { toast.error("Failed to load invoices"); return; }
99	      const now = new Date();
100	      setInvoices((data || []).map((inv: any) => inv.status === "sent" && isAfter(now, new Date(inv.due_date)) ? { ...inv, status: "overdue" } : inv));
101	      setLoading(false);
102	      return;
103	    }
104	
105	    const { data, error } = await supabase
106	      .from("invoices")
107	      .select("*")
108	      .eq("user_id", session.user.id)
109	      .order("created_at", { ascending: false });
110	
111	    if (error) {
112	      toast.error("Failed to load invoices");
113	      return;
114	    }
115	
116	    // Auto-mark overdue invoices
117	    const now = new Date();
118	    const updated = (data || []).map(inv => {
119	      if (inv.status === "sent" && isAfter(now, new Date(inv.due_date))) {
120	        return { ...inv, status: "overdue" };
121	      }
122	      return inv;
123	    });
124	
125	    setInvoices(updated);
126	    setLoading(false);
127	  };
128	
129	  useEffect(() => {
130	    fetchInvoices();
131	    fetchBusinessSettings();
132	  }, [workspaceId]);
133	
134	  const fetchBusinessSettings = async () => {
135	    const { data: { session } } = await supabase.auth.getSession();
136	    if (!session) return;
137	    const { data } = await supabase
138	      .from("business_settings")
139	      .select("business_name, business_email, business_phone, business_address, logo_url, tax_id, default_currency, default_tax_rate, default_payment_terms")
140	      .eq("user_id", session.user.id)
141	      .single();
142	    if (data) setBusinessSettings(data as any);
143	  };
144	
145	  const handleDelete = async (id: string) => {
146	    const { error } = await supabase.from("invoices").delete().eq("id", id);
147	    if (error) {
148	      toast.error("Failed to delete invoice");
149	      return;
150	    }
151	    toast.success("Invoice deleted");
152	    fetchInvoices();
153	  };
154	
155	  const handleDuplicate = async (invoice: Invoice) => {
156	    const { data: { session } } = await supabase.auth.getSession();
157	    if (!session) return;
158	
159	    // Get items for the invoice
160	    const { data: items } = await supabase
161	      .from("invoice_items")
162	      .select("*")
163	      .eq("invoice_id", invoice.id);
164	
165	    const date = new Date();
166	    const invNum = `INV-${date.getFullYear()}${String(date.getMonth() + 1).padStart(2, "0")}-${Math.floor(Math.random() * 10000).toString().padStart(4, "0")}`;
167	
168	    const { data: newInvoice, error } = await supabase
169	      .from("invoices")
170	      .insert({
171	        user_id: session.user.id,
172	        invoice_number: invNum,
173	        client_name: invoice.client_name,
174	        client_email: invoice.client_email,
175	        issue_date: new Date().toISOString().split("T")[0],
176	        due_date: invoice.due_date,
177	        currency: invoice.currency,
178	        subtotal: invoice.subtotal,
179	        total: invoice.total,
180	        status: "draft",
181	      })
182	      .select()
183	      .single();
184	
185	    if (error || !newInvoice) {
186	      toast.error("Failed to duplicate invoice");
187	      return;
188	    }
189	
190	    if (items && items.length > 0) {
191	      await supabase.from("invoice_items").insert(
192	        items.map((item) => ({
193	          invoice_id: newInvoice.id,
194	          description: item.description,
195	          quantity: item.quantity,
196	          unit_price: item.unit_price,
197	          total: item.total,
198	        }))
199	      );
200	    }
201	
202	    toast.success("Invoice duplicated as draft");
203	    fetchInvoices();
204	  };
205	
206	  const handleStatusChange = async (id: string, status: string) => {
207	    const { error } = await supabase
208	      .from("invoices")
209	      .update({ status })
210	      .eq("id", id);
