741	                value={terms}
742	                onChange={(e) => setTerms(e.target.value)}
743	                placeholder="Payment terms and conditions"
744	                className="mt-1"
745	                rows={3}
746	              />
747	            </div>
748	          </div>
749	
750	          {/* Actions */}
751	          <div className="flex justify-end gap-3 pt-4 border-t border-border">
752	            <Button variant="outline" onClick={() => onOpenChange(false)}>
753	              Cancel
754	            </Button>
755	            <Button
756	              onClick={handleSubmit}
757	              disabled={loading}
758	              className="bg-bronze hover:bg-bronze/90"
759	            >
760	              {loading ? "Saving..." : editingInvoice ? "Update Invoice" : "Create Invoice"}
761	            </Button>
762	          </div>
763	        </div>
764	      </DialogContent>
765	    </Dialog>
766	    </>
767	  );
768	};
